        </div>
      </div>

      <div className="bg-white/5 backdrop-blur-xl rounded-2xl p-6 border border-white/10">
        <h3 className="text-lg font-bold mb-4">Recent Bookings</h3>
        <div className="space-y-3 max-h-64 overflow-y-auto">
